    # Attempt to clean common date string artifacts only if necessary for common formats
    date_str_cleaned = date_str.replace('th', '').replace('st', '').replace('nd', '').replace('rd', '').replace('the ', '').replace('dated ', '').replace('issued ', '').strip()
    try:
        # Prioritize YYYY-MM-DD or MM/DD/YYYY, then try generic parsing
        if re.match(r'^\d{4}-\d{2}-\d{2}$', date_str_cleaned):
            return pd.to_datetime(date_str_cleaned, format='%Y-%m-%d', errors='coerce')
        elif re.match(r'^\d{2}/\d{2}/\d{4}$', date_str_cleaned):
            return pd.to_datetime(date_str_cleaned, format='%m/%d/%Y', errors='coerce')
        else:
            # Fallback to a few common non-numeric formats
            return pd.to_datetime(date_str_cleaned, errors='coerce')
    except Exception:
        return pd.NaT

